  ('colonel-7fec267e-moex-00204', 'colonel-7fec267e', 'colonel-7fec267e-moex-111-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '授予利益之行政處分，其內容係提供一次或連續之金錢，嗣後經撤銷者， 關於返還受領給付之敘述，下列何者錯誤？', '["確認返還範圍之處分未確定前，不得移送行政執行", "應返還給付之範圍準用民法有關不當得利之規定", "受益人拒絕返還所受領之給付時，行政機關應向行政法院提起給付訴訟", "行政機關請求返還時，應以書面行政處分確認返還範圍，並限期命受益 人返還之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00205', 'colonel-7fec267e', 'colonel-7fec267e-moex-111-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政處分之廢棄，下列敘述何者錯誤？', '["違法行政處分產生形式存續力後，相對人即不得再依行政爭訟程序，要 求撤銷", "違法授益性行政處分之撤銷，應考慮當事人是否有信賴保護之適用", "行政機關對違法行政處分，限於未產生形式存續力前，得依職權撤銷", "法定救濟期間屆滿後，發生有利相對人之新事實者，相對人得請求行政 程序再開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00206', 'colonel-7fec267e', 'colonel-7fec267e-moex-111-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '新北市政府與臺北市政府締結行政契約，依行政程序法規定，下列敘述何 者正確？', '["當事人之一方得就相對人契約之履行，依書面約定之方式，為必要之 指導", "締約機關所屬公法人之其他機關於契約關係外行使公權力，致相對人履 行契約義務而顯增費用，相對人得向締約機關請求損失補償", "當事人之一方為防止對公益之重大危害，得於必要範圍內終止契約", "因有情事重大變更，非當時所得預料，而依原約定顯失公平者，當事人 之一方得請求他方適當調整契約內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
